// ---- GitHub → Automa Import ----
// Clicks GitHub's native "Download raw file" button on a blob page.
// Console logs are prefixed [Automa Import] — filter by that in DevTools (F12 → Console).

(function () {
  console.log('[Automa Import] Step 1: Workflow started. URL =', location.href);

  // Must be on a GitHub blob (file view) page
  if (!location.href.match(/^https:\/\/github\.com\/[^/]+\/[^/]+\/blob\//)) {
    console.log('[Automa Import] Step 2: FAIL — not on a GitHub blob page');
    alert(
      '[Automa Import] Please run this workflow while viewing a GitHub file page.\n\n' +
      'Example URL:\n' +
      'https://github.com/kotaoue/helloAutoma/blob/<branch>/workflows/<name>.json'
    );
    automaNextBlock({ data: 'Error: not a GitHub blob page' });
    return;
  }
  console.log('[Automa Import] Step 2: GitHub blob page confirmed');

  // Find the "Download raw file" button in the GitHub toolbar
  var btn = document.querySelector('[aria-label="Download raw file"]');
  if (!btn) {
    console.log('[Automa Import] Step 3: FAIL — "Download raw file" button not found in page');
    alert(
      '[Automa Import] Could not find the "Download raw file" button on this page.\n\n' +
      'Make sure you are viewing a file on GitHub (not a folder or the repo root).'
    );
    automaNextBlock({ data: 'Error: download button not found' });
    return;
  }
  console.log('[Automa Import] Step 3: Found "Download raw file" button, clicking…');

  btn.click();

  console.log('[Automa Import] Step 4: SUCCESS — download triggered');
  automaNextBlock({ data: 'Downloaded' });
})();
